example.code:
class PaymentProvider(Protocol):
    def charge(self, amount_cents: int, token: str) -> str: ...

class StripeAdapter(PaymentProvider):
    def __init__(self, stripe_client: StripeClient) -> None:
        self._client = stripe_client

    def charge(self, amount_cents: int, token: str) -> str:
        response = self._client.payment_intents.create(
            amount=amount_cents, currency="usd", payment_method=token
        )
        return response.id
